// Cargo.toml
// [package]
// name = "my-tool"
// version = "0.1.0"
// edition = "2021"
//
// [dependencies]
// clap = { version = "4", features = ["derive"] }
// anyhow = "1"

// src/main.rs
use clap::Parser;
use anyhow::Result;

#[derive(Parser)]
#[command(name = "my-tool", version, about = "A useful CLI tool")]
struct Cli {
    /// Input file to process
    input: String,

    /// Enable verbose output
    #[arg(short, long)]
    verbose: bool,
}

fn main() -> Result<()> {
    let cli = Cli::parse();

    if cli.verbose {
        println!("Processing: {}", cli.input);
    }

    my_tool::run(&cli.input)?;
    Ok(())
}

// src/lib.rs
use anyhow::{Context, Result};
use std::fs;

pub fn run(input_path: &str) -> Result<()> {
    let content = fs::read_to_string(input_path)
        .with_context(|| format!("Could not read file: {}", input_path))?;

    let line_count = content.lines().count();
    let word_count = content.split_whitespace().count();

    println!("Lines: {}", line_count);
    println!("Words: {}", word_count);

    Ok(())
}
